import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import './Profile.css';

export default function Profile() {
  const { user, updateUser, logout } = useAuth();
  const navigate = useNavigate();
  const [isEditing, setIsEditing] = useState(false);
  const [form, setForm] = useState({ name: '', department: '', course: '', rollNumber: '' });
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    if (user) {
      setForm({
        name: user.name || '',
        department: user.department || '',
        course: user.course || '',
        rollNumber: user.rollNumber || '',
      });
    }
  }, [user]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setMessage('');
    try {
      const userId = user.id || user._id;
      const res = await api.put(`/users/${userId}`, form);
      updateUser(res.data);
      setMessage('Profile updated successfully.');
      setIsEditing(false);
    } catch (err) {
      setMessage(err.response?.data?.message || 'Update failed');
    } finally {
      setSaving(false);
    }
  };

  if (!user) return null;

  const initials = user?.name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '?';
  const userRole = user?.role || 'user';
  const roleColor = userRole === 'admin' ? '#ef4444' : userRole === 'teacher' ? '#f59e0b' : '#10b981';

  return (
    <div className="profile-page">
      {/* Profile Header */}
      <div className="profile-header">
        <div className="profile-avatar">
          <div className="avatar-circle">
            {initials}
          </div>
          <div className="role-badge" style={{ backgroundColor: roleColor }}>
            {userRole.charAt(0).toUpperCase() + userRole.slice(1)}
          </div>
        </div>
        <div className="profile-info">
          <h1 className="profile-name">{user.name}</h1>
          <p className="profile-email">{user.email}</p>
          <button
            className="edit-profile-btn"
            onClick={() => setIsEditing(true)}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path>
              <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path>
            </svg>
            Edit Profile
          </button>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="profile-tabs">
        <button
          className={`tab-btn ${activeTab === 'overview' ? 'active' : ''}`}
          onClick={() => setActiveTab('overview')}
        >
          Overview
        </button>
        <button
          className={`tab-btn ${activeTab === 'details' ? 'active' : ''}`}
          onClick={() => setActiveTab('details')}
        >
          Details
        </button>
        <button
          className={`tab-btn ${activeTab === 'activity' ? 'active' : ''}`}
          onClick={() => setActiveTab('activity')}
        >
          Activity
        </button>
      </div>

      {/* Tab Content */}
      <div className="profile-content">
        {activeTab === 'overview' && (
          <div className="tab-content">
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-icon">📚</div>
                <div className="stat-info">
                  <h3>{userRole === 'student' ? 'Courses' : 'Classes'}</h3>
                  <p>{user.course || user.department || 'Not specified'}</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">🆔</div>
                <div className="stat-info">
                  <h3>Roll Number</h3>
                  <p>{user.rollNumber || 'Not assigned'}</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">📧</div>
                <div className="stat-info">
                  <h3>Email</h3>
                  <p>{user.email}</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'details' && (
          <div className="tab-content">
            <div className="details-grid">
              <div className="detail-card">
                <h3>Personal Information</h3>
                <div className="detail-item">
                  <span className="detail-label">Full Name</span>
                  <span className="detail-value">{user.name}</span>
                </div>
                <div className="detail-item">
                  <span className="detail-label">Email Address</span>
                  <span className="detail-value">{user.email}</span>
                </div>
                <div className="detail-item">
                  <span className="detail-label">User Role</span>
                  <span className="detail-value">{userRole.charAt(0).toUpperCase() + userRole.slice(1)}</span>
                </div>
              </div>
              <div className="detail-card">
                <h3>Academic Information</h3>
                <div className="detail-item">
                  <span className="detail-label">Department</span>
                  <span className="detail-value">{user.department || 'Not provided'}</span>
                </div>
                <div className="detail-item">
                  <span className="detail-label">Course</span>
                  <span className="detail-value">{user.course || 'Not provided'}</span>
                </div>
                <div className="detail-item">
                  <span className="detail-label">Roll Number</span>
                  <span className="detail-value">{user.rollNumber || 'Not assigned'}</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'activity' && (
          <div className="tab-content">
            <div className="activity-card">
              <h3>Recent Activity</h3>
              <div className="activity-list">
                <div className="activity-item">
                  <div className="activity-icon">📝</div>
                  <div className="activity-info">
                    <p>Profile updated</p>
                    <span className="activity-time">Recently</span>
                  </div>
                </div>
                <div className="activity-item">
                  <div className="activity-icon">🔐</div>
                  <div className="activity-info">
                    <p>Account created</p>
                    <span className="activity-time">{new Date(user.createdAt || Date.now()).toLocaleDateString()}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Edit Modal */}
      {isEditing && (
        <div className="edit-modal-overlay">
          <div className="edit-modal">
            <div className="edit-modal-header">
              <h2>Edit Profile</h2>
              <button
                className="close-btn"
                onClick={() => setIsEditing(false)}
              >
                ✕
              </button>
            </div>
            <form onSubmit={handleSubmit} className="edit-form">
              {message && (
                <div className={`message ${message.includes('failed') ? 'error' : 'success'}`}>
                  {message}
                </div>
              )}

              <div className="form-group">
                <label className="form-label">Full Name</label>
                <input
                  type="text"
                  className="form-input"
                  name="name"
                  value={form.name}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label className="form-label">Email Address</label>
                <input
                  type="email"
                  className="form-input"
                  value={user.email}
                  disabled
                />
              </div>

              <div className="form-group">
                <label className="form-label">Department</label>
                <input
                  type="text"
                  className="form-input"
                  name="department"
                  value={form.department}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group">
                <label className="form-label">Course</label>
                <input
                  type="text"
                  className="form-input"
                  name="course"
                  value={form.course}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group">
                <label className="form-label">Roll Number</label>
                <input
                  type="text"
                  className="form-input"
                  name="rollNumber"
                  value={form.rollNumber}
                  onChange={handleChange}
                />
              </div>

              <div className="form-actions">
                <button
                  type="button"
                  className="btn btn-secondary"
                  onClick={() => setIsEditing(false)}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn btn-primary"
                  disabled={saving}
                >
                  {saving ? 'Saving...' : 'Save Changes'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
